import yaml

REQUIRED_SECTIONS = [
    "objectives",
    "key_terms",
    "theory",
    "worked_examples",
    "class_practice",
    "homework",
    "solutions"
]

def validate_yaml(yaml_string):
    try:
        data = yaml.safe_load(yaml_string)
    except yaml.YAMLError as e:
        return False, f"YAML Parsing Error: {e}"

    # Check root keys
    if "lesson" not in data or "sections" not in data:
        return False, "Missing 'lesson' or 'sections'"

    sections = data["sections"]

    section_types = [s.get("type") for s in sections]

    # Check required sections
    for req in REQUIRED_SECTIONS:
        if req not in section_types:
            return False, f"Missing section: {req}"

    # Count constraints
    def count_items(section_name):
        for s in sections:
            if s["type"] == section_name:
                return len(s.get("items", []))
        return 0

    if count_items("worked_examples") != 4:
        return False, "Must have exactly 4 worked examples"

    if count_items("class_practice") != 5:
        return False, "Must have exactly 5 class problems"

    if count_items("homework") != 5:
        return False, "Must have exactly 5 homework problems"

    # Diagram check
    for s in sections:
        if s["type"] in ["worked_examples", "class_practice", "homework"]:
            for item in s.get("items", []):
                if "diagram" not in item:
                    return False, "Missing diagram in a problem/example"

    return True, "YAML is valid"


if __name__ == "__main__":
    with open("lesson.yaml", "r") as f:
        yaml_string = f.read()

    valid, message = validate_yaml(yaml_string)
    print(message)
